glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  layout(std140) uniform ALPHA_TEST_DATA {
    float alphaThreshold;
  };
#endif
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
in vec4 color;
in vec2 uv0;
layout(std140) uniform MaskBlock {
  vec4 colors[6];
  vec4 heights[6];
  vec2 iResult;
  float tiltAngle;
  float corrugationType;
};
uniform sampler2D cc_spriteTexture;
const float EPSILON = 0.001;
const float HALF = 0.5;
const float MAX_LAYERS = 6.0;
const float FULL_CIRCLE = 360.0;
const float POURED_IN = 1.0;
const float POURED_OUT = 2.0;
const float POURED_IN_AMPLITUDE = 0.08;
const float POURED_IN_ANGULAR_VELOCITY = 10.0;
const float POURED_IN_FREQUENCY = 10.0;
const float POURED_OUT_AMPLITUDE = 0.03;
const float POURED_OUT_ANGULAR_VELOCITY = 5.0;
const float POURED_OUT_FREQUENCY = 6.0;
vec2 rotatePoint(vec2 uv, float angle, vec2 center) {
  float c = cos(angle);
  float s = sin(angle);
  float ox = center.x;
  float oy = center.y;
  mat3 m = mat3(
    c,   0.0 - s,  (1.0 - c) * ox + s * oy,
    s,   c,        (1.0 - c) * oy - s * ox,
    0.0, 0.0,     1.0
  );
  vec3 ret = m * vec3(uv.x, uv.y, 0.0);
  return ret.xy;
}
void calculateCenter(inout vec2 center, float angle, float waterHeight, float tanAngle, float ratio) {
  bool toLeft = sin(angle) >= 0.0;
  bool isBottomHit = tanAngle / ratio > 2.0 * waterHeight;
  bool isTopHit = tanAngle > ratio / (2.0 * waterHeight);
  if (waterHeight < HALF) {
    if (isBottomHit) {
      center.x = sqrt(2.0 * waterHeight / tanAngle * ratio) / 2.0;
      center.y = 1.0 - sqrt(2.0 * waterHeight * tanAngle / ratio) / 2.0;
      if (isTopHit) {
        center.y = HALF;
        center.x = waterHeight;
      }
    }
    if (!toLeft) center.x = 1.0 - center.x;
  } else {
    bool isTopHitHigh = tanAngle > 2.0 * ratio * (1.0 - waterHeight);
    bool isBottomHitHigh = tanAngle > ratio / (2.0 * (1.0 - waterHeight));
    if (isTopHitHigh) {
      center.x = sqrt(2.0 * ratio * (1.0 - waterHeight) / tanAngle) / 2.0;
      center.y = sqrt(2.0 * ratio * (1.0 - waterHeight) * tanAngle) / 2.0 / ratio;
      if (isBottomHitHigh) {
        center.y = HALF;
        center.x = 1.0 - waterHeight;
      }
    }
    if (toLeft) center.x = 1.0 - center.x;
  }
}
float getWaveOffset(vec2 uv, float angle) {
  bool toLeft = sin(angle) >= 0.0;
  bool isPouredIn = abs(corrugationType - POURED_IN) < 0.01;
  bool isPouredOut = abs(corrugationType - POURED_OUT) < 0.01;
  if (!isPouredIn && !isPouredOut) return 0.0;
  float amplitude = isPouredIn ? POURED_IN_AMPLITUDE : POURED_OUT_AMPLITUDE;
  float angularVelocity = isPouredIn ? POURED_IN_ANGULAR_VELOCITY : POURED_OUT_ANGULAR_VELOCITY;
  float frequency = isPouredIn ? POURED_IN_FREQUENCY : POURED_OUT_FREQUENCY;
  float direction = toLeft ? 1.0 : -1.0;
  return amplitude * sin((angularVelocity * uv.x) + (frequency * cc_time.x) * direction);
}
float drawWater(vec2 uv, float angle, float waterHeight, int layerCount, int currentLayerIndex) {
  float ratio = iResult.y / iResult.x;
  vec2 center = vec2(HALF, 1.0 - waterHeight);
  float tanAngle = abs(tan(angle));
  calculateCenter(center, angle, waterHeight, tanAngle, ratio);
  uv.y = uv.y * ratio;
  uv -= vec2(center.x, center.y * ratio);
  vec2 rotatedUv = rotatePoint(uv, angle, vec2(0.0));
  float waveOffset = 0.0;
  if (currentLayerIndex == layerCount - 1) {
    waveOffset = getWaveOffset(rotatedUv, angle);
  }
  return (rotatedUv.y > waveOffset) ? 1.0 : 0.0;
}
int getActiveLayerCount() {
  int count = 0;
  for (int i = 0; i < 6; i++) {
    if (heights[i].x > EPSILON) count++;
  }
  return count;
}
vec4 frag () {
  vec4 col = texture(cc_spriteTexture, uv0);
  if (col.a < EPSILON) discard;
  float angle = radians(mod(tiltAngle, FULL_CIRCLE));
  int layerCount = getActiveLayerCount();
  float heightSum = 0.0;
  float hit = 0.0;
  for (int i = 0; i < 6; i++) {
    if (heights[i].x < EPSILON) continue;
    heightSum += heights[i].x;
    hit = drawWater(uv0, angle, heightSum, layerCount, i);
    if (hit > 0.0) {
      col *= colors[i];
      break;
    }
  }
  if (hit < EPSILON) discard;
  return col;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

